import{_ as a,o as t,a as i,ag as o}from"./chunks/framework.1whTfjCw.js";const u=JSON.parse('{"title":"Security","description":"","frontmatter":{},"headers":[],"relativePath":"tnk/security.md","filePath":"tnk/security.md","lastUpdated":1784506044000}'),n={name:"tnk/security.md"};function r(s,e,l,d,c,h){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h1><h2 id="threat-model" tabindex="-1">Threat model <a class="header-anchor" href="#threat-model" aria-label="Permalink to &quot;Threat model&quot;">​</a></h2><p>Agent frameworks run with broad host privileges. Typical failure paths include:</p><ul><li>compromised package install scripts</li><li>malicious transitive dependencies</li><li>prompt-induced shell execution of unsafe commands</li><li>over-broad filesystem reads leaking credentials or private keys</li></ul><p>tnk limits failures to the sandbox VM.</p><h2 id="what-tnk-mitigates" tabindex="-1">What tnk mitigates <a class="header-anchor" href="#what-tnk-mitigates" aria-label="Permalink to &quot;What tnk mitigates&quot;">​</a></h2><h3 id="host-exposure" tabindex="-1">Host exposure <a class="header-anchor" href="#host-exposure" aria-label="Permalink to &quot;Host exposure&quot;">​</a></h3><ul><li>agent runtimes run inside sandbox VMs, not on the host shell</li><li>project-only mounts prevent full-home access</li><li>runtime variables are explicit, not ambient</li></ul><h3 id="supply-chain-containment" tabindex="-1">Supply-chain containment <a class="header-anchor" href="#supply-chain-containment" aria-label="Permalink to &quot;Supply-chain containment&quot;">​</a></h3><p>Profiles install package ecosystems inside sandbox boundaries. A bad package impacts the sandbox first, not your host root.</p><h3 id="predictable-teardown" tabindex="-1">Predictable teardown <a class="header-anchor" href="#predictable-teardown" aria-label="Permalink to &quot;Predictable teardown&quot;">​</a></h3><p><code>tnk shutdown</code> and lifecycle subcommands stop and reset all managed components.</p><h3 id="scriptability-and-verification" tabindex="-1">Scriptability and verification <a class="header-anchor" href="#scriptability-and-verification" aria-label="Permalink to &quot;Scriptability and verification&quot;">​</a></h3><p>JSON/NDJSON output and deterministic command shape let operators implement policy checks in shell tooling.</p><h3 id="network-isolation" tabindex="-1">Network isolation <a class="header-anchor" href="#network-isolation" aria-label="Permalink to &quot;Network isolation&quot;">​</a></h3><p>Restricted-profile sandboxes start with full network access during provisioning so scripts can download packages. After provisioning completes, tnk disables the network, sealing the sandbox boundary.</p><h3 id="residual-risk" tabindex="-1">Residual risk <a class="header-anchor" href="#residual-risk" aria-label="Permalink to &quot;Residual risk&quot;">​</a></h3><p>tnk does not make agents safe by default. The following actions create attack surface:</p><ul><li>Mounting sensitive files (private keys, <code>.env</code> files) into a sandbox</li><li>Executing untrusted binaries manually inside a sandbox</li><li>Overriding safe defaults (<code>bind_host</code>, <code>workspace_root</code>)</li><li>Running sandboxes as <code>root</code> or with elevated privileges</li></ul><p>Use <code>--audit-log</code> for any session where you need a record of what happened inside the sandbox.</p><h2 id="sandbox-isolation" tabindex="-1">Sandbox isolation <a class="header-anchor" href="#sandbox-isolation" aria-label="Permalink to &quot;Sandbox isolation&quot;">​</a></h2><p>tnk provides virtualization-backed isolation through two backends:</p><h3 id="lima" tabindex="-1">Lima <a class="header-anchor" href="#lima" aria-label="Permalink to &quot;Lima&quot;">​</a></h3><p>Linux VMs via VZ hypervisor. Full VM isolation is the primary security boundary.</p><h2 id="recommended-secure-operating-pattern" tabindex="-1">Recommended secure operating pattern <a class="header-anchor" href="#recommended-secure-operating-pattern" aria-label="Permalink to &quot;Recommended secure operating pattern&quot;">​</a></h2><ol><li>Keep <code>workspace_root</code> scoped to <code>~/code</code> (never <code>$HOME</code>).</li><li>Run agents through <code>tnk sandbox shell --profile pi</code>.</li><li>Keep host secrets outside project directories.</li><li>Use <code>tnk doctor</code> before major runtime changes.</li><li>Use <code>--audit-log</code> for sensitive sessions.</li><li>Use <code>tnk shutdown</code> when done.</li></ol><h2 id="limits" tabindex="-1">Limits <a class="header-anchor" href="#limits" aria-label="Permalink to &quot;Limits&quot;">​</a></h2><p>tnk contains agent execution. It cannot inspect agent reasoning, validate generated code for logic errors, or prevent social engineering inside the sandbox. Agents with valid credentials can still exfiltrate data through allowed network paths. Use <code>--audit-log</code> and least-privilege profiles to mitigate.</p><hr><p><strong>See also:</strong> <a href="/tnk/concepts">Concepts</a> · <a href="/tnk/sandbox">Sandbox</a> · <a href="/tnk/configuration">Configuration</a></p>',30)])])}const m=a(n,[["render",r]]);export{u as __pageData,m as default};
